/**
 * Which extraction strategy the uniform per-row pipeline used
(Task #277 removed the legacy hand-written parsers; every
upload is AI-first now):
- `cache`: an AI-discovered column-roles row was found and a
  generic role-based reader produced the rows (fast).
- `ai`: fell through to Gemini extraction (slow, but uniform).

 */
export type CustomerExtractPreviewExtractSource =
  (typeof CustomerExtractPreviewExtractSource)[keyof typeof CustomerExtractPreviewExtractSource];

export const CustomerExtractPreviewExtractSource = {
  cache: "cache",
  ai: "ai",
} as const;

export interface CustomerExtractPreview {
  customer: string;
  fileName: string;
  weekStart: string;
  /** True when the uploaded file's SHA-256 matched the most recent
successful import for this (week, customer) and the server
short-circuited without parsing or stashing anything. `sampleId`,
`rows`, `unmappedIds`, and `existingPunchCount` are all empty/zero
in this case and there is nothing for the caller to confirm.
Bulk-upload uses this to render "Already up to date" instead of
walking the dispatcher through a no-op preview.
 */
  skipped?: boolean;
  /**
   * ID of the stashed copy of the uploaded file. Pass back to /confirm-customer-file so the same bytes are re-parsed and committed. Null when `skipped=true`.
   * @nullable
   */
  sampleId: number | null;
  rows: CustomerExtractRow[];
  unmappedIds: UnmappedId[];
  /** Badge / employee IDs that the parser would have surfaced as unmapped
but were silently dropped because a per-customer "not a driver" rule
in `customer_ignored_externals` matched. Surfaced here so the
dispatcher knows the file did contain those people and can lift the
ignore from /admin/customer-ignored-externals if needed.
 */
  autoIgnoredIds?: UnmappedId[];
  /** Number of existing Customer-source punches for `(week, customer)` that this confirm would actually replace — i.e. excluding manual rows, inline-edited rows, and any rows belonging to a locked driver-week (all of which the wipe preserves). */
  existingPunchCount: number;
  /** Which extraction strategy the uniform per-row pipeline used
(Task #277 removed the legacy hand-written parsers; every
upload is AI-first now):
- `cache`: an AI-discovered column-roles row was found and a
  generic role-based reader produced the rows (fast).
- `ai`: fell through to Gemini extraction (slow, but uniform).
 */
  extractSource?: CustomerExtractPreviewExtractSource;
  /** True only when `extractSource` is `ai` AND the column-roles
cache row was successfully written for this file's header
signature. Tells the dispatcher the next upload of the same
xlsx layout will skip AI entirely and take the fast
`cache` → `readWithRoles` branch (sub-100ms). Always false
for cache hits, images, and PDFs (the schema cache is
xlsx-only today).
 */
  cacheWritten?: boolean;
  /** True when at least one model call in this upload's AI
extraction was served by the Gemini fallback after the
primary Claude call failed (Task #297). Opt-in per customer
via `customers.allowGeminiFallback`. Surfaced so the
customer-files panel can render an amber "Gemini fallback
used" badge — these rows should be reviewed more carefully
than a clean Claude extraction.
 */
  geminiFallbackUsed?: boolean;
  /** True when the uploaded file's SHA-256 matches the most
recent successful import for this (week, customer) AND
the caller passed `?force=1` so the server kept extracting
instead of short-circuiting with `skipped: true`. Set only
on the per-row Re-upload path (Task #358) — the bulk
upload path still skips identical bytes without ever
reaching this flag. The preview dialog uses it to render a
neutral "matches the last import you confirmed" note so
the dispatcher knows the re-upload is intentional and
isn't a regression.
 */
  sameAsLastImport?: boolean;
}

